/**
 * Errors around providing headers for each VSS request.
 */
public enum VssHeaderProviderError: Swift.Error {

    
    
    /**
     * Invalid data was encountered.
     */
    case InvalidData(
        /**
         * The error message.
         */error: String
    )
    /**
     * An external request failed.
     */
    case RequestError(
        /**
         * The error message.
         */error: String
    )
    /**
     * Authorization was refused.
     */
    case AuthorizationError(
        /**
         * The error message.
         */error: String
    )
    /**
     * An application-level error occurred specific to the header provider functionality.
     */
    case InternalError(
        /**
         * The error message.
         */error: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeVssHeaderProviderError: FfiConverterRustBuffer {
    typealias SwiftType = VssHeaderProviderError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> VssHeaderProviderError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .InvalidData(
            error: try FfiConverterString.read(from: &buf)
            )
        case 2: return .RequestError(
            error: try FfiConverterString.read(from: &buf)
            )
        case 3: return .AuthorizationError(
            error: try FfiConverterString.read(from: &buf)
            )
        case 4: return .InternalError(
            error: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: VssHeaderProviderError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .InvalidData(error):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(error, into: &buf)
            
        
        case let .RequestError(error):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(error, into: &buf)
            
        
        case let .AuthorizationError(error):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(error, into: &buf)
            
        
        case let .InternalError(error):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(error, into: &buf)
            
        }
    }
}


